#!/usr/bin/env python3
"""Wave 20 education facts — 20 Malayalam PSC topic categories."""

from __future__ import annotations

import random
import re

from refill_common import Candidate, add_candidate, interleave_candidates

MIXED = re.compile(r"[\u0D00-\u0D7F][a-zA-Z]|[a-zA-Z][\u0D00-\u0D7F]")
_ALLOWED_LATIN = re.compile(
    r"\b(RTE|NEP|UNESCO|SDG|IIT|IISc|TIFR|IIST|NCERT|UGC|AICTE|NCTE|"
    r"BCI|NMC|PCI|CABE|DIET|NUEPA|SCERT|DPEP|RUSA|NIPUN|NSQF|NTSE|NMMS|"
    r"ASER|UDISE|NIRF|NAAC|SQAAF|PARAKH|APAAR|CTET|IGNOU|JNV|KV|PMKVY|"
    r"SWAYAM|DIKSHA|NISHTHA|PM|SHRI|JRF|NET|SET|KVPY|INSPIRE|NEET|JEE|"
    r"GATE|CAT|MBA|CBSE|ICSE|NIOS|SSA|RMSA|HECI|PM|POSHAN|ICAR|IIM|NIT|"
    r"IIIT|BHU|TISS|NIFT|NID|SPA|AMU|JNU|AIIMS|MBBS|BDS|PhD|M\.Ed|B\.Ed)\b",
    re.I,
)
_LATIN4 = re.compile(r"[a-zA-Z]{4,}")


def _pool(items: list[str], correct: str) -> list[str]:
    return [x for x in items if x != correct]


def _typed_pool(q: str, ans: str, pool: list[str]) -> list[str]:
    from option_type_utils import classify_answer_kind, option_kind

    kind = classify_answer_kind(q, ans)
    if kind == "year":
        filtered = [x for x in pool if option_kind(x) == "year"]
    elif kind == "person":
        filtered = [x for x in pool if classify_answer_kind(q, x) == "person"]
    elif kind == "place":
        filtered = [x for x in pool if classify_answer_kind(q, x) == "place"]
    else:
        filtered = [x for x in pool if option_kind(x) == "text"]
    return filtered if len({*filtered, ans}) >= 4 else pool


def _strip_allowed_latin(text: str) -> str:
    return _ALLOWED_LATIN.sub("", text)


def _has_stray_latin(text: str) -> bool:
    return bool(_LATIN4.search(_strip_allowed_latin(text)))


def _add(
    out: list[Candidate],
    existing: set[str],
    rng: random.Random,
    q: str,
    ans: str,
    wrong: list[str],
    diff: str = "medium",
    pool: list[str] | None = None,
) -> None:
    blob = q + ans + "".join(wrong)
    parts = [q, ans, *wrong]
    if any(MIXED.search(p) for p in parts):
        return
    if any(_has_stray_latin(p) for p in parts):
        return
    add_candidate(out, existing, rng, q, ans, wrong, diff, pool)


def _pairs(
    out: list[Candidate],
    existing: set[str],
    rng: random.Random,
    rows: list[tuple[str, str]],
    templates: list[str],
    pool_b: list[str],
    diff: str = "medium",
) -> None:
    for a, b in rows:
        for tmpl in templates:
            q = tmpl.format(a=a, b=b)
            eff = _typed_pool(q, b, pool_b)
            _add(out, existing, rng, q, b, _pool(eff, b)[:3], diff, eff)


def _pairs_rev(
    out: list[Candidate],
    existing: set[str],
    rng: random.Random,
    rows: list[tuple[str, str]],
    templates: list[str],
    pool_a: list[str],
    diff: str = "medium",
) -> None:
    for a, b in rows:
        for tmpl in templates:
            q = tmpl.format(a=a, b=b)
            eff = _typed_pool(q, a, pool_a)
            _add(out, existing, rng, q, a, _pool(eff, a)[:3], diff, eff)


def _emit(
    out: list[Candidate],
    existing: set[str],
    rng: random.Random,
    rows: list[tuple[str, str]],
    fwd: list[str],
    rev: list[str],
    pool_a: list[str],
    pool_b: list[str],
    diff: str = "medium",
) -> None:
    _pairs(out, existing, rng, rows, fwd, pool_b, diff)
    _pairs_rev(out, existing, rng, rows, rev, pool_a, diff)


def _emit_qa(
    out: list[Candidate],
    existing: set[str],
    rng: random.Random,
    rows: list[tuple[str, str, list[str], str]],
    pool: list[str] | None = None,
) -> None:
    for q, ans, wrong, diff in rows:
        base = pool if pool else wrong + [ans]
        _add(out, existing, rng, q, ans, wrong, diff, base)

